      disable-tracking="${e.disableTracking??!1}"
      disable-cookies="${e.disableCookies??!1}"
      prefer-playback="${e.preferPlayback??!1}"
      start-time="${e.startTime==null?!1:e.startTime}"
      beacon-collection-domain="${e.beaconCollectionDomain??!1}"
